var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 흠! 흠!","JPN":"こほん。失礼いたします。","ENG":"Ahem... Hmm!","TWN":"咳咳，嗯！嗯！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여기 직원이시죠? 주문했던 옷을 찾으러 왔습니다만.","JPN":"ここの店員さんですわね？　注文した服を取りに来ました。","ENG":"Excuse me, do you work here? I came to pick up the outfit I ordered.","TWN":"你是這裡的員工吧？我來取訂購的衣服。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아, 할로윈 코스튬을 주문해 주신 분이군요!","JPN":"あ、ハロウィン衣装をご注文くださった方ですね！","ENG":"Oh, you must have ordered a Halloween costume!","TWN":"啊，您是訂萬聖節服裝的那一位啊！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어디 보자...... 주문자 성함이 어떻게 되시죠?","JPN":"どれどれ……あの、注文された方のお名前は？","ENG":"Let's see... What's your name?","TWN":"我看看...... 訂購者大名是？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳으로 되어 있을 거예요. 대리인을 통해 주문했거든요.","JPN":"リベットだと思いますわ。代理人に頼んで注文しましたので。","ENG":"It should be under the name Rivet. I had someone order it on my behalf.","TWN":"應該是用里維名字訂的，因為透過代理人訂購的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아하. 기억나요. 그 토끼 머리띠를 쓰고 온 분 말씀이시죠?","JPN":"ああ、覚えてますよ。あのウサギのヘアバンドを付けていらっしゃった方ですよね？","ENG":"Oh, I remember. She was the lady with the bunny ears, right?","TWN":"啊啊，我想起來了，戴上兔子髮箍的那一位吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"분명 서큐버스 복장을 주문하셨는데......","JPN":"確か、サキュバス衣装を注文されましたが……","ENG":"If I remember correctly, she ordered a succubus outfit...","TWN":"明明訂購了女妖服裝的......"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"서큐버스요. 특별 요구사항으로 끝내주게 섹시하게 만들어 달라고 써 두셨더라고요.","JPN":"サキュバスです。特別要求事項として、最高にセクシーに作ってほしいと書いてありました。","ENG":"A succubus outfit. She even wrote a note asking us to make it extra sexy.","TWN":"女妖啊，因為留紙條要求說，做成特別性感的服裝。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......그 멍청이가!!","JPN":"……あのバカ！？","ENG":"That moron!","TWN":"......那個笨蛋！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네? 뭐라고 하셨죠?","JPN":"はい？　何か？","ENG":"Excuse me? Did you say something?","TWN":"啊？你說什麼了？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 아무것도 아니에요.","JPN":"な、何でもありません。","ENG":"Oh, it's n-nothing.","TWN":"沒、沒事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그보다 옷은 완성됐나요?","JPN":"それより、服は完成しましたか？","ENG":"Well, is the outfit ready?","TWN":"話說回來，衣服完成了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"물론 일정에 못 맞췄다고 해도 충분히 이해합니다.","JPN":"もちろん、まだ未完成でも問題ありませんわ。","ENG":"I completely understand if you haven't met the deadline.","TWN":"當然，即使無法按照時程完成，我也會充分理解。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 파렴치한......","JPN":"そんな恥知らずな……","ENG":"Such a lewd...","TWN":"那種無恥的…"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":" 아니, 특별한 옷을 만드는 건 역시 어려운 일일 테니까요.","JPN":" いいえ、特別な服を作ることはさぞ難しいでしょう。","ENG":" Uh, I mean, such a special outfit would surely take a long time to put together.","TWN":" 沒事，做成特別的衣服果然是很困難的事情呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그럼 전 이만 가 보겠습니다. 내년 할로윈 때 다시 오죠!","JPN":"そ、それでは失礼いたします。来年のハロウィンにまた来ますわ！","ENG":"W-well, I'd better get going! I'll come back next Halloween!","TWN":"那、那麼我該回去了，明年萬聖節的時候我會再來的！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄아악?!","JPN":"きゃああ！？","ENG":"Eeek?!","TWN":"呃啊啊？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"옷 찾으러 왔어, 이교도 마녀들아.","JPN":"服を取りに来たぞ、異教徒の魔女たち。","ENG":"I'm here for my costume, heretic witches.","TWN":"我來取衣服的，你們這些邪道魔女啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"분명 오늘까지 완성된다고 했지?","JPN":"確か、今日までに完成するって言ってたよね？","ENG":"You said it'd be ready by today, right?","TWN":"你說過今天可以完成的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"혹시라도 시간 더 필요하다고 하면 천국의 전통 마녀 접대법을 가르쳐줄 테니 그리 아시고.","JPN":"もしもっと時間がほしいと言うのなら、天国での伝統的な魔女の接し方を教えてやるから覚悟しろよ。","ENG":"If you tell me you need more time, I'll show you what they do to witches like you up in heaven.","TWN":"如果還需要時間的話，我會讓你嘗試天國的傳統魔女常用的教訓魔法。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이, 이봐요! 문을 그렇게 확 열면 어떡해요?! 다칠 뻔했잖아요!","JPN":"あ、あの！　急にドアを開けないでください！　危ないでしょう？","ENG":"H-hey, you shouldn't throw the door open like that! You almost hurt me!","TWN":"喂，喂！幹嘛用這麼大力開門啊？！差點撞傷了！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그야 문 앞에서 걸리적거린 네 책임이지.","JPN":"それはドアの前でぼーっとしていたあんたのせいだ。","ENG":"It's your fault for getting in the way.","TWN":"那是因為你站在門前慢吞吞的關係啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"우리 직장에선 <color=#ffd34c>걷어차라. 그러면 열릴 것이다</color>라고 가르치거든.","JPN":"うちの職場では<color=#ffd34c>蹴飛ばせ、さらば開かれん</color>と教えてるんだ。","ENG":"Where I work, they say, \\"<color=#ffd34c>Kick, and it shall be opened to you.</color>\\"","TWN":"在我們公司都會教<color=#ffd34c>踢吧，那就會打開的</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"걷어차긴 뭘 걷어차?! <color=#ffd34c>두드려라</color>겠지!","JPN":"蹴飛ばせ、じゃなくて<color=#ffd34c>叩けよ、</color>でしょう！","ENG":"Kick?! You mean <color=#ffd34c>knock</color>!","TWN":"踢什麼踢啊？！應該是 <color=#ffd34c>敲門</color>才對！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그랬나? 뭐 그거나 저거나 비슷비슷한 것 같은데.","JPN":"そうかな？　まぁ、どうでもいいけどね。","ENG":"Oh, is that right? To-may-to, to-mah-to.","TWN":"是嗎？都是差不多啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"어쨌든 나중에 허리 아프면 진단서 떼서 여기 교구장한테 연락해.","JPN":"とにかく、あとで体の異常を感じたら診断書を発行してここの敎区長に連絡しろ。","ENG":"Anyway, if your back gets sore later, contact the local bishop with your doctor's notes.","TWN":"如果以後腰痛的話，開一張診斷書跟這裡的主教聯絡吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"자, 명함 받아.","JPN":"ほら、名刺を受け取れ。","ENG":"Here, take my card.","TWN":"來，收一下名片。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이익......!","JPN":"ううっ……！","ENG":"Ugh!","TWN":"呃呃......！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자, 자. 진정하세요. 두 분.","JPN":"まぁまぁ、落ち着いてください。お客さん。","ENG":"There, there. Settle down, you two.","TWN":"來，鎮定點吧，兩位。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"다들 걱정 안 하셔도 돼요. 옷은 모두 완성됐답니다.","JPN":"心配することはありません。衣装は2着とも完成していますよ。","ENG":"Neither of you need to worry. The costumes are ready.","TWN":"大家不用擔心了，衣服都完成了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"히익!","JPN":"ひいっ！","ENG":"Eeek!","TWN":"咻咻！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"오오!","JPN":"おぉ！","ENG":"Ooh!","TWN":"喔喔！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나! 잠깐 내려와 볼래?","JPN":"ユナ！ ちょっと降りて来て！","ENG":"Yuna! Can you come down here for a second?","TWN":"尤娜！妳來一下！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으으으...... 부르셨어요?","JPN":"ううう……お呼びですか？","ENG":"Urff... Did you want to see me?","TWN":"呃……什麼事？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머나, 많이 피곤해 보이네. 괜찮은 거니?","JPN":"あら、ずいぶん疲れてるみたいね。大丈夫？","ENG":"Oh my, you look exhausted. Are you alright?","TWN":"哎呀，妳看起來很疲憊，妳還好嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드에게 바느질을 가르치느라 밤을 샜거든요.","JPN":"イングリッドに縫い物を教えるために徹夜したんです。","ENG":"I was up all night teaching Ingrid how to sew.","TWN":"我熬夜教英格麗縫紉技術了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래? 생각보다 열심히 하네. 금방 포기할 줄 알았는데.","JPN":"そうなの？ 思った以上に頑張ってるのね。すぐに諦めると思ったんだけど。","ENG":"Really? She's been more persistent than I expected. I thought she'd give up right away.","TWN":"是嗎？這麼認真，還以為妳會早早地放棄呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그보다 할로윈 코스튬을 주문한 손님이 오셨거든.","JPN":"それより、ハロウィン衣装を注文されたお客さんがいらっしゃったの。","ENG":"Anyway, our customers are here to pick up their Halloween costumes.","TWN":"對了，訂購萬聖節服裝的客人來了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"벽장에 가면 만들어둔 옷이 있을 거야. 좀 가져다 줄래?","JPN":"クローゼットに完成した服があるから、持ってきてくれる？","ENG":"Could you go fetch them from the closet?","TWN":"壁櫥裡有做好的衣服，幫我拿一下吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네, 알겠어요!","JPN":"はい、わかりました！","ENG":"Sure, got it!","TWN":"嗯，好的！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"두 분께서는 절 따라오세요. 갈아입는 곳을 알려드릴게요.","JPN":"お二人さんはこちらへどうぞ。試着室へご案内いたします。","ENG":"Please follow me, ladies. I'll show you to the changing room.","TWN":"兩位請跟我來，我帶你們到更衣室。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우와......","JPN":"うわぁ……","ENG":"Whoa...","TWN":"哇……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"크흠, 흠!","JPN":"コホン、コホン！","ENG":"Hmm, Hmm!","TWN":"咳咳，咳！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"오, 오해는 하지 말아주셨으면 좋겠군요.","JPN":"ご、誤解しないでいただきたいですわね。","ENG":"P-please do not misunderstand.","TWN":"請、請不要誤會。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"전 격조 높은 맥크레디 가문의 정당한 후계자입니다. 절대 이런 옷을 좋아하진 않아요.","JPN":"私は高貴なマクレディー家の正当なる後継者です。こんな服なんか好みではありません。","ENG":"I am the rightful heir to the respected MacCready family. I do not relish in such obscenity.","TWN":"我可是有著高品位血統的麥克蕾蒂家族的正式繼承人，絕對不是喜歡這種服裝的人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"이건 전적으로 어떤 파렴치한 취향을 가진 용병의 음모 때문에......","JPN":"これは破廉恥趣味な傭兵の陰謀のせいで……","ENG":"This was all a conspiracy by a certain vulgar mercenary—","TWN":"這是因為有無恥癖好的傭兵陰謀才……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"정말 예뻐요! 멋있어요!","JPN":"本当にかわいい！　素敵です！","ENG":"Wow! You look gorgeous!","TWN":"真好看！很帥啊！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그, 그래요?","JPN":"そ、そうかしら。","ENG":"R-really?","TWN":"是、是嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"흐음. 확실히 라우라가 이런 스타일에 강하다니까.","JPN":"ふーん。確かにラウラはこんなスタイルに強いわね。","ENG":"Hmm. Laura sure has a knack for stuff like this.","TWN":"嗯，蘿拉確實很會做這類衣服呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"사이즈가 조금 작은 것 같긴 하지만, 잘 어울려요.","JPN":"サイズが少し小さいようですが、よく似合ってますよ。","ENG":"It might be a bit tight, but it looks good on you.","TWN":"尺寸好像小了點，但蠻好看的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"뭐, 제 취향이라는 건 아니지만 듣고 보니 제 우아함과 잘 어우러지는 것 같기도 하네요.","JPN":"まぁ、私の好みというわけではありませんが……\\n言われてみれば、私のエレガントな雰囲気に調和しているかもしれませんね。","ENG":"Well, I suppose it does go well with my sophisticated mien... that is not to say that I fancy it in any way.","TWN":"當然，這並不是我喜歡的類型，但聽妳們這麼說，感覺這衣服好像也挺適合我的優雅姿態。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"바로 이거야.","JPN":"まさにこれだ。","ENG":"This is it!","TWN":"就是這個！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"이 박력! 카리스마! 13일의 살인마도 눈을 마주치지 못할 야성의 스피릿!","JPN":"この迫力！ カリスマ性！ 13日の殺人鬼も目を合わせられないほどの野生のスピリッツ！","ENG":"The sheer wild energy! It's enough to make Jason look like a Catholic school boy!","TWN":"這個魄力！這個魅力！以及連惡魔也不敢與妳對望的野性感！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"마음에 들었어, 이교도 언니. 이따가 예배용 와인 한 병 가져다 줄게.","JPN":"気に入った、異教徒のお姉ちゃん。あとで礼拝用のワインを一本持ってきてあげるよ。","ENG":"I like what you've done, heretic lady. I'll even fetch you a bottle of communion wine later.","TWN":"我喜歡這個，異教徒姐姐的風格。等等拿一瓶祭拜時用的紅酒給妳。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 전통적인 소재와 최신의 트렌드를 결합한 제 회심의 역작이에요.","JPN":"ふふっ。クラシックな素材と最新トレンドを融合した私の会心の力作なんです。","ENG":"Hah hah, it sure is my masterpiece. I've combined classic materials with the latest trends.","TWN":"哼哼，這可是我按照最新潮流趨勢並採用傳統材料而製成的驚天大作。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마음에 든다니 저도 기쁘네요.","JPN":"気に入っていただけて嬉しいです。","ENG":"I'm glad you like it.","TWN":"您這麼滿意，我也很開心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저어...... 그런데 수녀님이라고 하지 않았어요?","JPN":"あの……ところで、シスターと言ってませんでしたか？","ENG":"Um... But didn't you say you're a nun?","TWN":"可是…… 您不是修女嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런 옷을 입어도 안 혼나요?","JPN":"そんな服を着て怒られないんでしょうか？","ENG":"Won't you get in trouble if you wear something like that?","TWN":"穿那種衣服，不會引人非議嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"어허. 괜찮아.","JPN":"いやいや、大丈夫。","ENG":"Meh, I'll be fine.","TWN":"嗯…… 沒關係。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"우리 기적심의회의 모토는 <color=#ffd34c>천사는 가까이, 하지만 사탄은 더 가까이</color>거든.","JPN":"アタシたち、第9奇跡審議会のモットーは<color=#ffd34c>天使と親しく、だが悪魔にはもっと親しく</color>なんだ。","ENG":"The motto of the Miracle Investigation Council is \\"<color=#ffd34c>Keep angels close, but the devil closer.</color>\\"","TWN":"我們第九奇蹟議會的座右銘是<color=#ffd34c>離天使近一點，離撒旦更近一點</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"더구나 오늘은 할로윈이잖아.","JPN":"しかも今日はハロウィンだろう。","ENG":"Besides, it's Halloween today.","TWN":"再說了，今天可是萬聖節。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"1년에 단 하루, 이교도처럼 놀아도 벼락 안 맞는 날이라고.","JPN":"1年にたった一度だけ、異教徒みたいに遊んでも祟らない日だよ。","ENG":"It's the only day of the year when we won't get smote for partying like heretics.","TWN":"一年只有一次，即使裝扮的像異教徒，也不會被天打雷劈。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그...... 그래요?","JPN":"そ……そうなんですか？","ENG":"R-really?","TWN":"是……是嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"이번엔 또 누구죠?! 왜 다들 예의 없이 문을 걷어차고...","JPN":"今度はまたどなたですか？　どうしてみんなドアを蹴飛ばして……無礼ですわ！","ENG":"Who could it be this time? Why does everyone have to kick the door open so rudely—","TWN":"這次又是誰啊？！怎麼都這麼無禮，踹門就進來了……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"...응?","JPN":"……うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"저건 설마...... 침식체?","JPN":"あれはもしかして……侵食体？","ENG":"Isn't that... a Corrupted Object?","TWN":"那不會是……侵蝕體吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국에서 알려드립니다.</color>","JPN":"<color=#ffd34c>都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>Attention, citizens. This is an announcement from City Management.</color>","TWN":"<color=#ffd34c>城市管理局通知。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 시내에서 하급 침식체가 다수 출현했다는 소식입니다.</color>","JPN":"<color=#ffd34c>ただ今、市内に下級侵食体が多数出現しました。</color>","ENG":"<color=#ffd34c>We have received reports of multiple low-level Corrupted Objects being sighted downtown.</color>","TWN":"<color=#ffd34c>目前，市內有眾多低等侵蝕體出沒。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>담당 태스크포스가 긴급히 대응 중이니, 시민 여러분께서는 경보가 해제되기 전까지 안전한 곳에서 대기해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>担当のタスクフォースカンパニーが至急対応していますので、市民の皆さんは\\n警報が解除されるまで、安全なところで待機してください。</color>","ENG":"<color=#ffd34c>The respective TASKFORCEs with jurisdiction are responding to the situation immediately. Please take shelter in safe areas until the alert is lifted.</color>","TWN":"<color=#ffd34c>相關特遣勢力正在緊急應對，請各位市民在解除警報前，在安全的地方等候。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"침식체가 실내로 들이닥치는데 뭐가 긴급한 대응 중이라는 건가요, 대체!","JPN":"侵食体が室内に押し掛けているのに何が至急対応ですか、もう！","ENG":"Responding immediately? We've got C.O.s bursting into the cafe already!","TWN":"什麼緊急應對？這侵蝕體都闖到室內了！"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에, 에블린 언니! 이 도시에는 침식체가 잘 안 나타난다면서요?!","JPN":"エ、エヴリン姉さん！　この都市には侵食体はめったに現れないって言ってましたよね？","ENG":"E-Evelyn! I thought you said C.O.s don't appear very often in this city!","TWN":"伊、伊芙琳姐姐！妳不是說這個城市幾乎不會出現侵蝕體嗎？！"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......맞아. 이상한 일이네.","JPN":"……そのはずだけど、おかしいわね。","ENG":"I did. This is strange.","TWN":"……沒錯，好奇怪。"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 지금은 고민이나 하고 있을 때가 아냐.","JPN":"でも今は悩んでる場合じゃないわ。","ENG":"But now is not the time to sit around feeling puzzled.","TWN":"但現在沒時間想這些。"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"일단 나가 보자. 하급 침식체라도 일반인들에게는 위험해.","JPN":"とりあえず出てみましょう。下級侵食体とはいえ、一般人には危険な存在だから。","ENG":"Let's head out there. Even low-level C.O.s can be dangerous for ordinary people.","TWN":"先出去看看吧，即使是低等侵蝕體，對普通人還是很危險的。"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"저, 저도 돕겠어요!","JPN":"わ、私も手を貸しますわ！","ENG":"I-I'll assist you!","TWN":"我、我也要幫忙！"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"맥크레디 가문의 후계자로서, 평범한 사람들이 다치게 내버려 둘 수는 없습니다.","JPN":"マクレディー家の後継者として、民間人を見殺しにするわけにはいきません。","ENG":"As a MacCready, I cannot allow innocent civilians be hurt on my watch.","TWN":"作為麥克蕾蒂家族的繼承人，我不能眼睜睜地看著無辜的市民受到傷害。"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"좋아요. 그럼 우리 귀여운 수녀님은......","JPN":"わかりました。では、可愛いシスターは……","ENG":"Great. And as for our cute little nun...","TWN":"好吧，那我們可愛的修女……"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어디 갔지?","JPN":"えっ、いない？","ENG":"Where did she go?","TWN":"去哪裡了？"},"stage":{"bg":"CAFE_STREGA","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"다들 안에서 뭘 꾸물거리고 있어?","JPN":"お前ら、何をぐずぐずしている？","ENG":"What's taking you all so long to get out here?","TWN":"妳們在裡面磨蹭什麼呢？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"올해 할로윈의 기념비적인 첫 번째 트릭 오어 트릿이잖아.","JPN":"今年のハロウィンの記念碑のような、初トリック・オア・トリートじゃないか。","ENG":"This is the first trick or treat of this year's Halloween. It's a monumental moment!","TWN":"這可是今年萬聖節第一個充滿紀念意義的“不給糖就搗蛋”。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"사탕을 잔뜩 준비해 놓는 게 좋을 거야. 침식체 친구들.","JPN":"キャンディをいっぱい用意しておいたほうがいいぞ。侵食体ども。","ENG":"I hope you've got plenty of treats ready for me, C.O. buddies.","TWN":"侵蝕體朋友，你們準備好足夠的糖了吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_CHAINSAW_START"},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"내 장난은 많이 따끔할 거거든.","JPN":"アタシのいたずらはかなり痛いんだ。","ENG":"Because I'm going to kick your butt with my tricks!","TWN":"我搗蛋起來可是又猛又疼的哦。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};